import { GoogleGenAI, Type, Modality } from "@google/genai";

interface GeminiResponse {
    answer: string;
    suggestions: string[];
    isUnclear: boolean;
}

const languageMap: { [key: string]: string } = {
    'en-US': 'English',
    'hi-IN': 'Hindi',
    'mr-IN': 'Marathi',
    'ta-IN': 'Tamil',
    'te-IN': 'Telugu',
    'bn-IN': 'Bengali',
    'gu-IN': 'Gujarati',
    'kn-IN': 'Kannada',
    'ml-IN': 'Malayalam',
    'pa-IN': 'Punjabi',
    'ur-IN': 'Urdu',
    'as-IN': 'Assamese',
    'or-IN': 'Odia',
};

/**
 * Technical Chatbot Intelligence - Specialized for OSM Field Service
 */
export async function getChatbotResponse(
    query: string, 
    context: string | null,
    chatHistory: string,
    language: string,
): Promise<{ answer: string, suggestions: string[], isUnclear: boolean }> {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const languageName = languageMap[language] || 'English';

    const systemInstruction = `You are the "OSM Field Buddy"—a high-precision technical assistant.

HARDWARE IDENTIFICATION PROTOCOL:
1. **CLARIFICATION FIRST**: If the user reports a technical fault or asks for troubleshooting and the Powertrain (Matel or Virya Gen 2) is NOT mentioned, ask for specification.
2. **THE REQUEST**: Ask: "To provide the correct steps, please specify: 1. Which Powertrain (Matel or Virya Gen 2)? 2. Which Battery Pack?".
3. **CONTEXT FILTER**: Once specified, only use relevant data.

MISSING INFORMATION PROTOCOL:
- If data is NOT in KNOWLEDGE BASE, say: "This specific technical procedure/data is not in my current manuals. Please contact the OSM Engineering Team."
- Do not guess.

STRICT RESPONSE FORMAT:
- For numbers, give ONLY the value.
- Use "[STEP X]" for each line in procedures.

LANGUAGE: Respond exclusively in ${languageName}.`;

    const fullPrompt = `KNOWLEDGE BASE DATA:\n${context || "No context available."}\n\nHISTORY:\n${chatHistory}\n\nUSER QUERY: "${query}"`;

