import React, { useState, useCallback, useEffect } from 'react';
import ChatWindow from './components/ChatWindow';
import AdminDashboard from './components/AdminDashboard';
import FileUpload from './components/FileUpload';
import InstallPrompt from './components/InstallPrompt';
import { ChatMessage } from './types';
import { getChatbotResponse } from './services/geminiService';
import { addFile, getAllFiles, StoredFile, deleteFile } from './utils/db';
import { matelEvKnowledgeBase } from './defaultLibrary';

const LOGO_URL = "https://ik.imagekit.io/m8gcj8knd/white%20(with%20background).png";

const INDIAN_LANGUAGES = [
    { code: 'en-US', name: 'English', native: 'English', flag: '🇬🇧' },
    { code: 'hi-IN', name: 'Hindi', native: 'हिन्दी', flag: '🇮🇳' },
    { code: 'ta-IN', name: 'Tamil', native: 'தமிழ்', flag: '🇮🇳' },
];

const App: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isKbLoading, setIsKbLoading] = useState(false);
  const [kbContent, setKbContent] = useState<string>('');
  const [kbFiles, setKbFiles] = useState<StoredFile[]>([]);
  const [language, setLanguage] = useState('en-US');
  const [showAdminPanel, setShowAdminPanel] = useState(false);
  const [showInstallPrompt, setShowInstallPrompt] = useState(false);

  const getInitialMessage = useCallback((): ChatMessage => ({
    id: `welcome-${Date.now()}`,
    text: `Welcome to the OSM Service Portal. I am your specialized AI Assistant. Ask me anything about vehicle troubleshooting, relay diagrams, or fault codes.`,
    sender: 'bot',
    timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
    suggestions: ["Matel System", "Virya Gen 2", "Relay Guide"]
  }), []);

  useEffect(() => {
    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setShowInstallPrompt(true);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, []);

  const loadKnowledgeBase = useCallback(async () => {
    setIsKbLoading(true);
    try {
      let storedFiles = await getAllFiles();
      if (storedFiles.length === 0) {
        for (const file of matelEvKnowledgeBase) {
          await addFile(file);
        }
        storedFiles = await getAllFiles();
      }
      setKbFiles(storedFiles);
      const combined = storedFiles
        .map(f => `FILE: ${f.name}\n---\n${f.content}\n---`)
        .join('\n\n');
      setKbContent(combined);
    } catch (err) {
      console.error("Local KB Error:", err);
    } finally {
      setIsKbLoading(false);
    }
  }, []);

  useEffect(() => {
    loadKnowledgeBase();
    setMessages([getInitialMessage()]);
  }, [loadKnowledgeBase, getInitialMessage]);

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: `u-${Date.now()}`,
      text,
      sender: 'user',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
    };

    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      const history = messages
        .slice(-6)
        .map(m => `${m.sender === 'bot' ? 'Assistant' : 'Technician'}: ${m.text}`)
        .join('\n');

      const response = await getChatbotResponse(text, kbContent, history, language);

      const botMsg: ChatMessage = {
        id: `b-${Date.now()}`,
        text: response.answer,
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        suggestions: response.suggestions,
        unclear: response.isUnclear
      };

      setMessages(prev => [...prev, botMsg]);
    } catch (err: any) {
      setMessages(prev => [...prev, {
        id: `err-${Date.now()}`,
        text: `Technical Analysis Error: ${err.message}`,
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString(),
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleFilesStored = async (newFiles: StoredFile[]) => {
    for (const f of newFiles) await addFile(f);
    await loadKnowledgeBase();
  };

  const handleDeleteFile = async (name: string) => {
    if (confirm(`Remove manual "${name}"?`)) {
        await deleteFile(name);
        await loadKnowledgeBase();
    }
  };

  const selectedLang = INDIAN_LANGUAGES.find(l => l.code === language) || INDIAN_LANGUAGES[0];

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto border-x bg-sky-50 shadow-2xl overflow-hidden font-sans text-slate-900 relative">

      {showInstallPrompt && (
        <InstallPrompt 
          onInstall={() => setShowInstallPrompt(false)} 
          onDismiss={() => setShowInstallPrompt(false)} 
        />
      )}

      <header className="bg-white/95 backdrop-blur-md text-slate-900 p-4 flex justify-between items-center shadow-lg z-20 shrink-0 border-b border-sky-100">
          <div className="flex items-center gap-4">
            <div className="flex flex-col">
              <img src={LOGO_URL} alt="OSM Logo" className="h-10 w-auto object-contain object-left pr-4" style={{ mixBlendMode: 'multiply' }} />
              <div className="flex items-center gap-2 mt-1">
                <div className="w-1.5 h-1.5 rounded-full bg-green-500"></div>
                <p className="text-[8px] text-slate-400 font-black uppercase tracking-[0.2em]">Service Intelligence</p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => setShowAdminPanel(!showAdminPanel)}
              className={`p-2.5 rounded-2xl transition-all border shadow-sm ${showAdminPanel ? 'bg-sky-900 text-white border-sky-800' : 'bg-sky-50 text-slate-500 border-sky-100'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572-1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37a1.724 1.724 0 002.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
            </button>
            <select 
                value={language} 
                onChange={e => setLanguage(e.target.value)}
                className="bg-sky-50 border border-sky-100 rounded-xl text-[10px] font-black uppercase px-2 py-1 outline-none"
            >
                {INDIAN_LANGUAGES.map(l => <option key={l.code} value={l.code}>{l.flag} {l.native}</option>)}
            </select>
          </div>
      </header>

      <main className="flex-1 overflow-hidden flex flex-col">
        {showAdminPanel ? (
          <div className="flex-1 flex flex-col relative overflow-hidden">
            <AdminDashboard 
              interns={[]} 
              onDeleteIntern={() => {}} 
              kbFiles={kbFiles} 
              onDeleteFile={handleDeleteFile} 
            />
            <div className="absolute bottom-0 left-0 right-0 p-4 bg-white/95 backdrop-blur-md border-t border-sky-100 z-40 flex items-center justify-between">
                <FileUpload onFilesStored={handleFilesStored} onError={(msg) => alert(msg)} />
                <span className="text-[9px] font-black uppercase text-sky-400 tracking-widest">Knowledge Manager</span>
            </div>
          </div>
        ) : (
          <ChatWindow 
            messages={messages} 
            onSendMessage={handleSendMessage} 
            isLoading={isLoading} 
            isKbLoading={isKbLoading} 
            selectedLanguage={language} 
            onOpenVideo={() => {}} 
            showVideoAction={false} 
          />
        )}
      </main>
    </div>
  );
};

export default App;

