    const parts = processedText.split(/(SAFETY WARNING:|PRO-TIP:|\[STEP \d+\]|^\s*[•\-*]|\*\*.*?\*\*|\b\d+(?:\.\d+)?[V|v|A|a]\b|\bPin \d+[a-z]?\b|\b\d+ Ohm\b|\bErr-\d+\b)/gm);

    const contentNodes: React.ReactNode[] = parts.map((part, index) => {
