                <span className="text-4xl font-black text-white tracking-tighter">{text}</span>
            </div>
        );
    }
    return processContent(text);
  };

  const playFromBuffer = (buffer: AudioBuffer) => {
    if (!audioContextRef.current) return;
    const source = audioContextRef.current.createBufferSource();
    source.buffer = buffer;
    source.connect(audioContextRef.current.destination);
    source.playbackRate.value = 1.25; // Slightly faster for efficiency
    source.onended = () => setIsSpeaking(false);
    source.start();
    sourceRef.current = source;
    setIsSpeaking(true);
  };

  const handlePlayAudio = async () => {
    if (isSpeaking) {
      if (sourceRef.current) { try { sourceRef.current.stop(); } catch(e) {} }
      setIsSpeaking(false);
      return;
    }

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }

    // Check cache for immediate playback
    if (audioCacheRef.current) {
        playFromBuffer(audioCacheRef.current);
        return;
    }

    setIsAudioLoading(true);
    try {
      const base64Audio = await generateSpeech(message.text, language);
      if (!base64Audio) { setIsAudioLoading(false); return; }

      const audioBytes = decodeBase64(base64Audio);
      const buffer = await decodeAudioData(audioBytes, audioContextRef.current, 24000, 1);

      // Store in cache for next time
      audioCacheRef.current = buffer;

      playFromBuffer(buffer);
    } catch (err) {
      setIsSpeaking(false);
    } finally {
      setIsAudioLoading(false);
    }
  };

  return (
    <div className={`flex flex-col gap-1 w-full ${isUser ? 'items-end' : 'items-start'} animate-in slide-in-from-bottom-2 duration-300`}>
