import { GoogleGenAI, Type, Modality } from "@google/genai";

interface GeminiResponse {
    answer: string;
    suggestions: string[];
    isUnclear: boolean;
}

const languageMap: { [key: string]: string } = {
    'en-US': 'English',
    'hi-IN': 'Hindi',
    'mr-IN': 'Marathi',
    'ta-IN': 'Tamil',
    'te-IN': 'Telugu',
    'bn-IN': 'Bengali',
    'gu-IN': 'Gujarati',
    'kn-IN': 'Kannada',
    'ml-IN': 'Malayalam',
    'pa-IN': 'Punjabi',
    'ur-IN': 'Urdu',
    'as-IN': 'Assamese',
    'or-IN': 'Odia',
};

/**
 * Technical Chatbot Intelligence - Specialized for OSM Field Service
 */
export async function getChatbotResponse(
    query: string, 
    context: string | null,
    chatHistory: string,
    language: string,
): Promise<{ answer: string, suggestions: string[], isUnclear: boolean }> {
  const apiKey = process.env.API_KEY;
  const targetLanguageName = languageMap[language] || 'English';

  if (!apiKey || apiKey === "") {
      return {
          answer: "⚠️ SYSTEM CONFIGURATION ERROR: The 'API_KEY' is missing in Vercel environment variables.",
          suggestions: ["Setup Guide", "Contact Admin"],
          isUnclear: true
      };
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    const systemInstruction = `MANDATORY: You MUST respond EXCLUSIVELY in ${targetLanguageName} language using its native script. 
Even though the training manuals are in English, the intern only speaks ${targetLanguageName}.

Persona: You are "OSM Mentor"—a patient senior technician.

RULES:
1. **LANGUAGE**: Provide the 'answer' and all 'suggestions' in ${targetLanguageName}.
2. **TERMINOLOGY**: Keep technical parts (e.g., "MCU", "Pin 1", "48V") in English script inside the ${targetLanguageName} sentences.
3. **SAFETY**: Start troubleshooting responses with a "SAFETY WARNING:" block in ${targetLanguageName}.
4. **GROUNDING**: Use ONLY the provided knowledge base. 

Output MUST be a valid JSON object.`;

    const fullPrompt = `TARGET LANGUAGE: ${targetLanguageName}\n\nKNOWLEDGE BASE:\n${context || "No context provided."}\n\nHISTORY:\n${chatHistory}\n\nUSER QUERY: "${query}"\n\nREMINDER: Provide the JSON response in ${targetLanguageName}.`;

    const result = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [{ parts: [{ text: fullPrompt }] }],
        config: {
            systemInstruction,
            temperature: 0.1,
            seed: 42,
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    answer: { type: Type.STRING },
                    suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
                    isUnclear: { type: Type.BOOLEAN }
                },
                required: ["answer", "suggestions", "isUnclear"]
            }
        },
    });

    let responseText = result.text || "";

    const startIdx = responseText.indexOf('{');
    const endIdx = responseText.lastIndexOf('}') + 1;
    const cleanJson = responseText.substring(startIdx, endIdx);

    return JSON.parse(cleanJson) as GeminiResponse;

  } catch (error: any) {
    console.error("OSM AI Failure:", error);
    return {
        answer: "I am having trouble processing technical data. Please try again.",
        suggestions: ["Try English", "Retry"],
        isUnclear: true
    };
  }
}

export async function generateSpeech(text: string, language: string): Promise<string> {
    try {
        const apiKey = process.env.API_KEY;
        if (!apiKey) return '';
        const ai = new GoogleGenAI({ apiKey });
        const targetLanguageName = languageMap[language] || 'English';

        // Strip UI markers for better speech synthesis
        const cleanText = text
            .replace(/SAFETY WARNING:/g, 'Important safety warning.')
            .replace(/PRO-TIP:/g, 'Pro tip.')
            .replace(/\[STEP \d+\]/g, 'Step.')
            .replace(/!\[.*?\]\(.*?\)/g, '')
            .replace(/(https?:\/\/drive\.google\.com\/[^\s\n)]+)/g, '')
            .replace(/\*\*/g, '')
            .replace(/#/g, '')
            .trim()
            .substring(0, 1000);

        if (!cleanText) return '';

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-preview-tts',
            contents: [{ parts: [{ text: cleanText }] }],
            config: {
                systemInstruction: `You are an OSM Technical Assistant. Read the text clearly and fast in ${targetLanguageName}. Use a helpful but professional tone.`,
                responseModalities: [Modality.AUDIO],
                thinkingConfig: { thinkingBudget: 0 },
                speechConfig: { 
                    voiceConfig: { 
                        prebuiltVoiceConfig: { 
                            voiceName: 'Kore' 
                        } 
                    } 
                },
            },
        });
        return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || '';
    } catch (error) {
        console.error("Speech Gen Error:", error);
        return '';
    }
}

