import { GoogleGenAI, Type, Modality } from "@google/genai";

interface GeminiResponse {
    answer: string;
    suggestions: string[];
    isUnclear: boolean;
}

const languageMap: { [key: string]: string } = {
    'en-US': 'English',
    'hi-IN': 'Hindi',
    'mr-IN': 'Marathi',
    'ta-IN': 'Tamil',
    'te-IN': 'Telugu',
    'bn-IN': 'Bengali',
    'gu-IN': 'Gujarati',
    'kn-IN': 'Kannada',
    'ml-IN': 'Malayalam',
    'pa-IN': 'Punjabi',
    'ur-IN': 'Urdu',
    'as-IN': 'Assamese',
    'or-IN': 'Odia',
};

/**
 * Technical Chatbot Intelligence - Specialized for OSM Field Service
 */
export async function getChatbotResponse(
    query: string, 
    context: string | null,
    chatHistory: string,
    language: string,
): Promise<{ answer: string, suggestions: string[], isUnclear: boolean }> {
  const apiKey = process.env.API_KEY;
  const targetLanguageName = languageMap[language] || 'English';

  if (!apiKey || apiKey === "") {
      return {
          answer: "⚠️ SYSTEM CONFIGURATION ERROR: The 'API_KEY' is missing in Vercel environment variables.",
          suggestions: ["Setup Guide", "Contact Admin"],
          isUnclear: true
      };
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // Strengthened instructions: Native script is mandatory for the answer and suggestions.
    const systemInstruction = `MANDATORY: You MUST respond EXCLUSIVELY in ${targetLanguageName} language using its native script (e.g., Devanagari for Hindi/Marathi, Tamil script for Tamil, etc.). 
The training manuals provided are in English, but you must translate all explanations into ${targetLanguageName} for the user.

Persona: You are "OSM Mentor"—a senior technical expert for Omega Seiki Mobility.

RULES:
1. **SCRIPTS**: The entire 'answer' and all 'suggestions' strings MUST be written in the native script of ${targetLanguageName}.
2. **TECHNICAL TERMS**: Keep strictly technical IDs (like "MCU", "Pin 87", "48V", "VCU") in English/Latin characters within the translated sentences.
3. **STRUCTURE**: Start safety-related troubleshooting with a "SAFETY WARNING:" line in ${targetLanguageName}.
4. **SOURCE**: Use ONLY the provided knowledge base. If not found, set isUnclear to true.

Output MUST be a valid JSON object.`;

    const fullPrompt = `USER PREFERRED LANGUAGE: ${targetLanguageName}\n\nKNOWLEDGE BASE CONTEXT:\n${context || "No context provided."}\n\nCONVERSATION HISTORY:\n${chatHistory}\n\nCURRENT INTERN QUERY: "${query}"\n\nREMINDER: Output JSON with 'answer' and 'suggestions' strictly in ${targetLanguageName} script.`;

    const result = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [{ parts: [{ text: fullPrompt }] }],
        config: {
            systemInstruction,
            temperature: 0.1,
            seed: 42,
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    answer: { type: Type.STRING },
                    suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
                    isUnclear: { type: Type.BOOLEAN }
                },
                required: ["answer", "suggestions", "isUnclear"]
            }
        },
    });

    let responseText = result.text || "";

    const startIdx = responseText.indexOf('{');
    const endIdx = responseText.lastIndexOf('}') + 1;
    const cleanJson = responseText.substring(startIdx, endIdx);

    return JSON.parse(cleanJson) as GeminiResponse;

  } catch (error: any) {
    console.error("OSM AI Failure:", error);
    return {
        answer: "System error during translation. Please try again.",
        suggestions: ["Retry", "Switch to English"],
        isUnclear: true
    };
  }
}

export async function generateSpeech(text: string, language: string): Promise<string> {
    try {
        const apiKey = process.env.API_KEY;
        if (!apiKey) return '';
        const ai = new GoogleGenAI({ apiKey });
        const targetLanguageName = languageMap[language] || 'English';

        // Strip UI markers for better speech synthesis. 
        // We keep the actual content so the model has text to speak.
        const cleanText = text
            .replace(/SAFETY WARNING:/g, 'Attention.')
            .replace(/PRO-TIP:/g, 'Pro tip.')
            .replace(/\[STEP \d+\]/g, 'Step.')
            .replace(/!\[.*?\]\(.*?\)/g, '')
            .replace(/(https?:\/\/drive\.google\.com\/[^\s\n)]+)/g, '')
            .replace(/\*\*/g, '')
            .replace(/#/g, '')
            .trim();

        if (!cleanText) return '';

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-preview-tts',
            contents: [{ parts: [{ text: cleanText }] }],
            config: {
                // FIXED: Removed thinkingConfig which caused the 400 error.
                systemInstruction: `Speak naturally and helpfully as a senior mentor in ${targetLanguageName}. Output ONLY the spoken audio.`,
                responseModalities: [Modality.AUDIO],
                speechConfig: { 
                    voiceConfig: { 
                        prebuiltVoiceConfig: { 
                            voiceName: 'Kore' 
                        } 
                    } 
                },
            },
        });
        return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || '';
    } catch (error) {
        console.error("Speech Generation Error:", error);
        return '';
    }
}

