import { GoogleGenAI, Type, Modality } from "@google/genai";

interface GeminiResponse {
    answer: string;
    suggestions: string[];
    isUnclear: boolean;
}

const languageMap: { [key: string]: string } = {
    'en-US': 'English',
    'hi-IN': 'Hindi',
    'mr-IN': 'Marathi',
    'ta-IN': 'Tamil',
    'te-IN': 'Telugu',
    'bn-IN': 'Bengali',
    'gu-IN': 'Gujarati',
    'kn-IN': 'Kannada',
    'ml-IN': 'Malayalam',
    'pa-IN': 'Punjabi',
    'ur-IN': 'Urdu',
    'as-IN': 'Assamese',
    'or-IN': 'Odia',
};

/**
 * Technical Chatbot Intelligence - Specialized for OSM Field Service
 */
export async function getChatbotResponse(
    query: string, 
    context: string | null,
    chatHistory: string,
    language: string,
): Promise<{ answer: string, suggestions: string[], isUnclear: boolean }> {
  const apiKey = process.env.API_KEY;
  const targetLanguageName = languageMap[language] || 'English';

  if (!apiKey || apiKey === "") {
      return {
          answer: "⚠️ SYSTEM CONFIGURATION ERROR: The 'API_KEY' is missing.",
          suggestions: ["Contact Admin"],
          isUnclear: true
      };
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // Using gemini-3-flash-preview for better performance and higher rate limits
    const systemInstruction = `You are "OSM Mentor"—a senior technical expert for Omega Seiki Mobility.

CORE KNOWLEDGE:
The context provided contains technical manuals and a MASTER SPREADSHEET (CSV format). 

AUTOMATIC DRAWING IMPORT RULES:
1. **SCAN FOR LINKS**: Every time a user asks a query, scan the spreadsheet rows for that topic.
2. **IDENTIFY DRAWING COLUMNS**: Look for columns named "Drawing", "Image", "Schematic", "Diagram", or any column containing a URL (especially Google Drive links).
3. **MANDATORY EXTRACTION**: If you find a drawing link in the row matching the user's issue, you MUST output it in the 'answer'.
4. **MARKDOWN FORMAT**: Format the drawing link EXACTLY like this: ![Technical Diagram](URL). This triggers the automatic drawing viewer in the chat.
5. **VISUAL FIRST**: A drawing is often more helpful than text. Never omit the link if it exists in the data.

RESPONSE RULES:
- Respond ONLY in the NATIVE SCRIPT of ${targetLanguageName}.
- Keep IDs like "VCU", "MCU", "Pin 1" in English script.
- Output MUST be a single valid JSON object.
- If information is missing, set isUnclear to true.`;

    const fullPrompt = `USER LANGUAGE: ${targetLanguageName}
CONTEXT DATA (Spreadsheets + Manuals):
${context || "No context provided."}

HISTORY:
${chatHistory}

USER QUERY: "${query}"

MANDATORY: If there is a Drawing or Link column for this topic in the spreadsheet above, include the URL in your answer as ![Diagram](URL).`;

    const result = await ai.models.generateContent({
        model: 'gemini-3-flash-preview', // High performance & high quota model
        contents: [{ parts: [{ text: fullPrompt }] }],
        config: {
            systemInstruction,
            temperature: 0.1,
            seed: 42,
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    answer: { type: Type.STRING },
                    suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
                    isUnclear: { type: Type.BOOLEAN }
                },
                required: ["answer", "suggestions", "isUnclear"]
            }
        },
    });

    const responseText = result.text || "";
    const startIdx = responseText.indexOf('{');
    const endIdx = responseText.lastIndexOf('}') + 1;
    const cleanJson = responseText.substring(startIdx, endIdx);

    return JSON.parse(cleanJson) as GeminiResponse;

  } catch (error: any) {
    console.error("OSM AI Failure:", error);

    // Specific check for Quota (429) errors
    if (error?.status === 429 || error?.message?.includes('quota') || error?.message?.includes('429')) {
        return {
            answer: "⚠️ SYSTEM OVERLOAD: We are receiving too many requests. Please wait 10 seconds and try again. The drawings are safe but the AI needs a moment to breathe.",
            suggestions: ["Retry Query", "Wait 10s"],
            isUnclear: true
        };
    }

    return {
        answer: "Connection error. Please check if your spreadsheet is still published and public.",
        suggestions: ["Refresh Page"],
        isUnclear: true
    };
  }
}

export async function generateSpeech(text: string, language: string): Promise<string> {
    try {
        const apiKey = process.env.API_KEY;
        if (!apiKey) return '';
        const ai = new GoogleGenAI({ apiKey });
        const targetLanguageName = languageMap[language] || 'English';

        const cleanText = text
            .replace(/SAFETY WARNING:/g, 'Warning.')
            .replace(/PRO-TIP:/g, 'Tip.')
            .replace(/\[STEP \d+\]/g, 'Step.')
            .replace(/!\[.*?\]\(.*?\)/g, 'Refer to the drawing on your screen.') 
            .replace(/(https?:\/\/[^\s\n)]+)/g, '')
            .replace(/[*#_~`>]/g, '')
            .replace(/\s+/g, ' ')
            .trim();

        if (!cleanText) return '';

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-preview-tts',
            contents: [{ parts: [{ text: `Speak this in ${targetLanguageName}: ${cleanText}` }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: { 
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } 
                },
            },
        });

        return response.candidates?.[0]?.content?.parts?.find(p => p.inlineData)?.inlineData?.data || '';
    } catch (error) {
        return '';
    }
}

